-- 특별휴가 신청서 템플릿 추가
INSERT OR IGNORE INTO templates (id, title, description, category, content, created_by, is_active) VALUES
('tpl-att-011', '특별휴가 신청서', '경조사 등 특별휴가 사용 시 작성', '근태/휴가', '<h1 style="text-align:center;font-size:20px">특 별 휴 가 신 청 서</h1><p><br></p><table><tr><th style="width:15%">성 명</th><td style="width:35%"></td><th style="width:15%">부 서</th><td style="width:35%"></td></tr><tr><th>직 급</th><td></td><th>사 번</th><td></td></tr></table><p><br></p><table><tr><th style="width:15%">휴가 종류</th><td>☐ 특별유급휴가 &nbsp; ☐ 기타</td></tr><tr><th>세부 사유</th><td>☐ 본인 결혼 (5일) &nbsp; ☐ 부모/배우자부모/배우자/자녀 장례 (3일) &nbsp; ☐ 조부모/배우자조부모/형제자매 장례 (1일) &nbsp; ☐ 기타 ( &nbsp; &nbsp; &nbsp; &nbsp; )</td></tr><tr><th>휴가 기간</th><td>&nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 ~ &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; 월 &nbsp; &nbsp; 일 (총 &nbsp; &nbsp; 일간)</td></tr><tr><th>상세 사유</th><td style="height:80px"></td></tr><tr><th>증빙 서류</th><td>☐ 가족관계증명원 &nbsp; ☐ 청첩장 &nbsp; ☐ 사망진단서 &nbsp; ☐ 기타 ( &nbsp; &nbsp; &nbsp; &nbsp; )</td></tr><tr><th>비상연락처</th><td></td></tr><tr><th>업무대행자</th><td>부서: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; 성명: &nbsp; &nbsp; &nbsp; &nbsp; &nbsp; &nbsp;</td></tr></table><p><br></p><p style="text-align:center;font-size:13px">위와 같이 특별휴가를 신청하오니 허가하여 주시기 바랍니다.</p><p style="text-align:center;font-size:13px">&nbsp; &nbsp; &nbsp; &nbsp; 년 &nbsp; &nbsp; &nbsp; 월 &nbsp; &nbsp; &nbsp; 일</p><p><br></p><p style="font-size:11px;color:#888">※ 특별유급휴가는 가족관계증명원 제출을 전제로 합니다.</p>', 'admin-001', 1);
